from tracer import trace, span

@trace(name="RAG_Request")
def handle_request(user_query):

    @span(name="Retrieve_Context")
    def get_docs(q):
        docs = db.search(q)
        # Log the exact chunk text so we know what the model saw
        span.log_metadata({"retrieved_text": [d.text for d in docs]})
        return docs

    @span(name="LLM_Generation")
    def generate(q, docs):
        prompt = f"Context: {docs}\nQuestion: {q}"
        # The decorator automatically captures the prompt, output, and tokens
        return call_llm(prompt)

    docs = get_docs(user_query)
    return generate(user_query, docs)
